#ifndef _KERNEL_H_
#define _KERNEL_H_

__kernel void
BFS_1( Node* g_graph_nodes, int* g_graph_edges, bool* g_graph_mask, bool* g_updating_graph_mask, bool *g_graph_visited, int* g_cost, int no_of_nodes) 
{
	int tid = get_global_id(0);
	if( tid < no_of_nodes && g_graph_mask[tid])
	{
		g_graph_mask[tid] = false;
		for(int i = g_graph_nodes[tid].starting; i < (g_graph_nodes[tid].no_of_edges + g_graph_nodes[tid].starting); i++)
		{
			int id = g_graph_edges[i];
			if(!g_graph_visited[id])
			{
				g_cost[id] = g_cost[tid] + 1;
				g_updating_graph_mask[id] = true;
			}
		}
	}
}

#endif 

#ifndef _KERNEL2_H_
#define _KERNEL2_H_

__kernel void
BFS_2( bool* g_graph_mask, bool *g_updating_graph_mask, bool* g_graph_visited, bool *g_over, int no_of_nodes)
{
	int tid = get_global_id(0);
	if( tid < no_of_nodes && g_updating_graph_mask[tid])
	{
		g_graph_mask[tid] = true;
		g_graph_visited[tid] = true;
		*g_over = true;
		g_updating_graph_mask[tid] = false;
	}
}

#endif
